import React, { useEffect, useState } from "react";
import "./Internship.css";

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const user = JSON.parse(localStorage.getItem("loggedInUser"));

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(data);
  }, []);

  const handleApply = (id) => {
    alert(`Applied to internship ID: ${id}`);
    // You can later store applied internships for the user here
  };

  const handleDelete = (id) => {
    const updated = internships.filter((item) => item.id !== id);
    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
  };

  const handleEdit = (id) => {
    alert(`Edit functionality for ID: ${id}`);
  };

  return (
    <div className="internship-container">
      <h2>Internship Opportunities</h2>
      {internships.length === 0 ? (
        <p>No internships available.</p>
      ) : (
        <div className="internship-list">
          {internships.map((item) => (
            <div key={item.id} className="internship-card">
              <h3>{item.title}</h3>
              <p>{item.description}</p>
              <p><strong>Company:</strong> {item.company}</p>
              <p><strong>Duration:</strong> {item.duration}</p>

              <div className="actions">
                {(user.role === "Admin" || user.role === "HR") && (
                  <>
                    <button onClick={() => handleEdit(item.id)}>Edit</button>
                    {user.role === "Admin" && (
                      <button onClick={() => handleDelete(item.id)}>Delete</button>
                    )}
                  </>
                )}

                {user.role === "Student" && (
                  <button onClick={() => handleApply(item.id)}>Apply</button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
